import{_ as a,c as n,a as s,o}from"./app-U7mDFV7x.js";const t={};function i(r,e){return o(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="mei-mappings-tools-src-tools-meimappings-js" tabindex="-1"><a class="header-anchor" href="#mei-mappings-tools-src-tools-meimappings-js"><span>MEI Mappings Tools (<code>src/tools/meiMappings.js</code>)</span></a></h1><p>Utility functions for mapping between MEI zones/measures and Annotorious annotations, as well as manipulating MEI documents.</p><hr><h2 id="overview" tabindex="-1"><a class="header-anchor" href="#overview"><span>Overview</span></a></h2><p>This module provides functions to:</p><ul><li>Convert MEI zones to Annotorious annotation objects and vice versa</li><li>Create, insert, and delete measures and zones in MEI</li><li>Move content between mdivs</li><li>Add imported pages to MEI</li><li>Manage multi-rests and additional zones</li></ul><hr><h2 id="functions" tabindex="-1"><a class="header-anchor" href="#functions"><span>Functions</span></a></h2><h3 id="meizone2annotorious-mei-zoneinput-pageuri" tabindex="-1"><a class="header-anchor" href="#meizone2annotorious-mei-zoneinput-pageuri"><span><code>meiZone2annotorious(mei, zoneInput, pageUri)</code></span></a></h3><p>Converts an MEI <code>&lt;zone&gt;</code> element to an Annotorious annotation object.</p><ul><li><strong>Parameters:</strong><ul><li><code>mei</code>: The MEI XML document</li><li><code>zoneInput</code>: The zone element or its ID</li><li><code>pageUri</code>: The image/page URI</li></ul></li></ul><hr><h3 id="annotorious2meizone-annot" tabindex="-1"><a class="header-anchor" href="#annotorious2meizone-annot"><span><code>annotorious2meiZone(annot)</code></span></a></h3><p>Converts an Annotorious annotation object to an MEI <code>&lt;zone&gt;</code> element.</p><ul><li><strong>Parameters:</strong><ul><li><code>annot</code>: The Annotorious annotation object</li></ul></li></ul><hr><h3 id="measuredetector2meizone-rect" tabindex="-1"><a class="header-anchor" href="#measuredetector2meizone-rect"><span><code>measureDetector2meiZone(rect)</code></span></a></h3><p>Creates a new MEI <code>&lt;zone&gt;</code> element from a rectangle (e.g., from a detector).</p><ul><li><strong>Parameters:</strong><ul><li><code>rect</code>: Object with <code>ulx</code>, <code>uly</code>, <code>lrx</code>, <code>lry</code> properties</li></ul></li></ul><hr><h3 id="generatemeasure" tabindex="-1"><a class="header-anchor" href="#generatemeasure"><span><code>generateMeasure()</code></span></a></h3><p>Creates and returns a new MEI <code>&lt;measure&gt;</code> element with a unique ID.</p><hr><h3 id="insertmeasure-xmldoc-measure-state-currentzone-pageindex-targetmdiv" tabindex="-1"><a class="header-anchor" href="#insertmeasure-xmldoc-measure-state-currentzone-pageindex-targetmdiv"><span><code>insertMeasure(xmlDoc, measure, state, currentZone, pageIndex, targetMdiv)</code></span></a></h3><p>Inserts a measure into the MEI file at the correct position, adjusting measure numbers and page breaks as needed.</p><ul><li><strong>Parameters:</strong><ul><li><code>xmlDoc</code>: The MEI XML document</li><li><code>measure</code>: The measure element to insert</li><li><code>state</code>: Vuex state</li><li><code>currentZone</code>: The zone associated with the measure</li><li><code>pageIndex</code>: Index of the page (zero-based)</li><li><code>targetMdiv</code>: The mdiv to insert into</li></ul></li></ul><hr><h3 id="getfollowingmeasuresbymeasure-measure" tabindex="-1"><a class="header-anchor" href="#getfollowingmeasuresbymeasure-measure"><span><code>getFollowingMeasuresByMeasure(measure)</code></span></a></h3><p>Returns an array of all measures following the given measure.</p><hr><h3 id="addzonetolastmeasure-xmldoc-zoneid" tabindex="-1"><a class="header-anchor" href="#addzonetolastmeasure-xmldoc-zoneid"><span><code>addZoneToLastMeasure(xmlDoc, zoneId)</code></span></a></h3><p>Adds a zone reference to the last measure in the MEI document.</p><hr><h3 id="createnewmdiv-xmldoc-aftermdivid" tabindex="-1"><a class="header-anchor" href="#createnewmdiv-xmldoc-aftermdivid"><span><code>createNewMdiv(xmlDoc, afterMdivId)</code></span></a></h3><p>Creates a new <code>&lt;mdiv&gt;</code> in the MEI document, optionally after a given mdiv.</p><ul><li><strong>Parameters:</strong><ul><li><code>xmlDoc</code>: The MEI XML document</li><li><code>afterMdivId</code>: (Optional) ID of the mdiv after which to insert</li></ul></li></ul><hr><h3 id="deletezone-xmldoc-id-state" tabindex="-1"><a class="header-anchor" href="#deletezone-xmldoc-id-state"><span><code>deleteZone(xmlDoc, id, state)</code></span></a></h3><p>Deletes a zone and its associated measures from the MEI document.</p><ul><li><strong>Parameters:</strong><ul><li><code>xmlDoc</code>: The MEI XML document</li><li><code>id</code>: The zone ID</li><li><code>state</code>: Vuex state</li></ul></li></ul><hr><h3 id="toggleadditionalzone-xmldoc-id-state" tabindex="-1"><a class="header-anchor" href="#toggleadditionalzone-xmldoc-id-state"><span><code>toggleAdditionalZone(xmlDoc, id, state)</code></span></a></h3><p>Toggles an additional zone for a measure, updating facsimile references and measure structure.</p><hr><h3 id="setmultirest-measure-val" tabindex="-1"><a class="header-anchor" href="#setmultirest-measure-val"><span><code>setMultiRest(measure, val)</code></span></a></h3><p>Sets or removes a multi-rest on a measure, updating following measure numbers as needed.</p><ul><li><strong>Parameters:</strong><ul><li><code>measure</code>: The measure element</li><li><code>val</code>: The multi-rest value (number or null)</li></ul></li></ul><hr><h3 id="movecontenttomdiv-xmldoc-firstmeasureid-targetmdivid-state" tabindex="-1"><a class="header-anchor" href="#movecontenttomdiv-xmldoc-firstmeasureid-targetmdivid-state"><span><code>moveContentToMdiv(xmlDoc, firstMeasureId, targetMdivId, state)</code></span></a></h3><p>Moves a sequence of measures (and related elements) to a different mdiv.</p><hr><h3 id="addimportedpage-xmldoc-index-url-width-height" tabindex="-1"><a class="header-anchor" href="#addimportedpage-xmldoc-index-url-width-height"><span><code>addImportedPage(xmlDoc, index, url, width, height)</code></span></a></h3><p>Adds a new page (surface and graphic) to the MEI document for an imported image.</p><ul><li><strong>Parameters:</strong><ul><li><code>xmlDoc</code>: The MEI XML document</li><li><code>index</code>: Page index</li><li><code>url</code>: Image URL</li><li><code>width</code>: Image width</li><li><code>height</code>: Image height</li></ul></li></ul><hr><h2 id="example-usage" tabindex="-1"><a class="header-anchor" href="#example-usage"><span>Example Usage</span></a></h2><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code><span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> meiZone2annotorious<span class="token punctuation">,</span> annotorious2meiZone<span class="token punctuation">,</span> insertMeasure<span class="token punctuation">,</span> createNewMdiv <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@/tools/meiMappings.js&#39;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Convert a zone to an annotation</span></span>
<span class="line"><span class="token keyword">const</span> annotation <span class="token operator">=</span> <span class="token function">meiZone2annotorious</span><span class="token punctuation">(</span>meiDoc<span class="token punctuation">,</span> zoneElem<span class="token punctuation">,</span> pageUri<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Convert an annotation to a zone</span></span>
<span class="line"><span class="token keyword">const</span> zone <span class="token operator">=</span> <span class="token function">annotorious2meiZone</span><span class="token punctuation">(</span>annotation<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Insert a new measure</span></span>
<span class="line"><span class="token function">insertMeasure</span><span class="token punctuation">(</span>meiDoc<span class="token punctuation">,</span> newMeasure<span class="token punctuation">,</span> state<span class="token punctuation">,</span> currentZone<span class="token punctuation">,</span> pageIndex<span class="token punctuation">,</span> targetMdiv<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Create a new mdiv</span></span>
<span class="line"><span class="token keyword">const</span> mdivId <span class="token operator">=</span> <span class="token function">createNewMdiv</span><span class="token punctuation">(</span>meiDoc<span class="token punctuation">)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,57)])])}const d=a(t,[["render",i]]),c=JSON.parse('{"path":"/meimapping.html","title":"MEI Mappings Tools (src/tools/meiMappings.js)","lang":"en-US","frontmatter":{},"git":{"updatedTime":1747234892000,"contributors":[{"name":"Hizkiel","username":"Hizkiel","email":"hizclick@gmail.com","commits":1,"url":"https://github.com/Hizkiel"}],"changelog":[{"hash":"addcf634062a696867cd389eb76f27f467f4a69a","time":1747234892000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Correcting the impits based on the pr comments"}]},"filePathRelative":"meimapping.md"}');export{d as comp,c as data};
